// Retornar status do CC Report
const result = $input.first().json;

console.log(JSON.stringify({
  timestamp: new Date().toISOString(),
  route: 'cc_report_manage/status',
  event: 'status_retrieved',
  level: 'info'
}));

// Se não há dados, retornar status inicial
const status = result.length > 0 ? result[0] : {
  cc_id: 'initial',
  entries_runned: 0,
  outputs_runned: 0,
  updated_at: new Date().toISOString()
};

return {
  statusCode: 200,
  body: status
};
